// src/App.jsx — fully responsive, large book, with Index panel and covers

import { useState, useRef, useEffect, useCallback } from "react";
import HTMLFlipBook from "react-pageflip";

import { DEFAULT_PAGES } from "./data/pages.js";
import BookPage from "./components/BookPage.jsx";
import BookIndex from "./components/BookIndex.jsx";
import ReferencePanel from "./components/ReferencePanel.jsx";
import NavBtn from "./components/NavBtn.jsx";
import KeyboardNav from "./components/KeyboardNav.jsx";
import LoginScreen from "./components/LoginScreen.jsx";
import AdminPanel from "./components/AdminPanel.jsx";

function useBookDimensions() {
  const [dim, setDim] = useState({ w: 420, h: 520, portrait: false });

  useEffect(() => {
    const calc = () => {
      const vw = window.innerWidth;
      const vh = window.innerHeight;
      const portrait = vw < 540; // single page on small phones

      if (portrait) {
        // Full-width single page
        const w = Math.floor(Math.min(vw * 0.88, 440));
        const h = Math.floor(Math.min(w * 1.3, vh * 0.6));
        setDim({ w, h, portrait: true });
      } else {
        // Two-page spread: each page w × h, total width 2w
        // Cap at 90vw total spread width, 80vh page height
        const maxSpreadW = vw * 0.9;
        const maxH = vh * 0.7;
        // target aspect 4:5 per page
        let w = Math.floor(maxSpreadW / 2);
        let h = Math.floor(w * 1.25);
        if (h > maxH) {
          h = Math.floor(maxH);
          w = Math.floor(h / 1.25);
        }
        // floor to even pixels to avoid sub-pixel glitches
        w = Math.max(w, 220);
        h = Math.max(h, 280);
        setDim({ w, h, portrait: false });
      }
    };
    calc();
    window.addEventListener("resize", calc);
    return () => window.removeEventListener("resize", calc);
  }, []);

  return dim;
}

// Custom cover component to display inside flip book
function CoverPage({ type, pageW, pageH }) {
  const isFront = type === "front";
  return (
    <div
      style={{
        width: pageW,
        height: pageH,
        background: "linear-gradient(135deg, #1e1b4b 0%, #312e81 50%, #1e1b4b 100%)",
        borderRadius: "4px",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        position: "relative",
        overflow: "hidden",
        boxShadow: "inset 0 0 30px rgba(0,0,0,0.3)",
      }}
    >
      {/* Decorative border */}
      <div
        style={{
          position: "absolute",
          inset: 12,
          border: "2px solid rgba(255,215,0,0.5)",
          borderRadius: "2px",
          pointerEvents: "none",
        }}
      />

      {/* Magical sparkles */}
      {[...Array(12)].map((_, i) => (
        <div
          key={i}
          style={{
            position: "absolute",
            top: `${Math.random() * 100}%`,
            left: `${Math.random() * 100}%`,
            fontSize: `${12 + Math.random() * 20}px`,
            opacity: 0.4 + Math.random() * 0.5,
            animation: `twinkle ${2 + Math.random() * 3}s ease-in-out infinite`,
            animationDelay: `${Math.random() * 2}s`,
            pointerEvents: "none",
          }}
        >
          {["✨", "⭐", "🌟", "💫", "⭐"][Math.floor(Math.random() * 5)]}
        </div>
      ))}

      {/* Cover Image Area */}
      <div
        style={{
          width: "70%",
          height: "45%",
          background: "url('https://cdn.pixabay.com/photo/2015/12/09/17/11/magic-book-1085246_640.jpg') center/cover",
          borderRadius: "12px",
          boxShadow: "0 10px 30px rgba(0,0,0,0.5), inset 0 1px 2px rgba(255,255,255,0.2)",
          marginBottom: "20px",
          border: "2px solid rgba(255,215,0,0.6)",
        }}
      />

      <h1
        style={{
          fontFamily: "'Bubblegum Sans', cursive",
          fontSize: `${Math.min(pageW * 0.09, 36)}px`,
          color: "#FFD700",
          textShadow: "0 2px 10px rgba(0,0,0,0.5), 0 0 20px rgba(255,215,0,0.3)",
          margin: "10px 0 5px",
          textAlign: "center",
          padding: "0 15px",
        }}
      >
        {isFront ? "Magic Story Book" : "The End"}
      </h1>

      <p
        style={{
          fontFamily: "'Nunito', sans-serif",
          fontSize: `${Math.min(pageW * 0.04, 16)}px`,
          color: "rgba(255,255,255,0.8)",
          textAlign: "center",
          margin: 0,
          padding: "0 20px",
        }}
      >
        {isFront 
          ? "Open the book to begin your magical journey..." 
          : "Thank you for reading! May magic stay with you always."}
      </p>

      {isFront && (
        <div
          style={{
            position: "absolute",
            bottom: 20,
            fontSize: `${Math.min(pageW * 0.05, 20)}px`,
            color: "rgba(255,215,0,0.5)",
            fontFamily: "'Bubblegum Sans', cursive",
          }}
        >
          ✨
        </div>
      )}
    </div>
  );
}

export default function App() {
  const [pages, setPages] = useState(DEFAULT_PAGES);
  const [currentPage, setCurrentPage] = useState(0);
  const [showRef, setShowRef] = useState(false);
  const [showIndex, setShowIndex] = useState(false);
  const [showLogin, setShowLogin] = useState(false);
  const [showAdmin, setShowAdmin] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const flipRef = useRef(null);
  const { w: pageW, h: pageH, portrait } = useBookDimensions();

  const onPage = useCallback((e) => {
    setCurrentPage(e.data);
    setShowRef(false);
  }, []);

  const prev = () => flipRef.current?.pageFlip().flipPrev();
  const next = () => flipRef.current?.pageFlip().flipNext();

  const goToPage = (i) => {
    flipRef.current?.pageFlip().flip(i);
    setCurrentPage(i);
  };

  // Create book with front cover and end cover
  const bookWithCovers = [
    { id: "front-cover", type: "cover", isFrontCover: true, isEndCover: false, content: null },
    ...pages,
    { id: "end-cover", type: "cover", isFrontCover: false, isEndCover: true, content: null }
  ];

  const totalBookPages = bookWithCovers.length;
  const bookProgress = totalBookPages > 1 ? currentPage / (totalBookPages - 1) : 0;
  const activePage = bookWithCovers[currentPage];

  // Spread width — in portrait mode only 1 page is shown
  const spreadW = portrait ? pageW : pageW * 2 + 4;

  return (
    <div
      style={{
        minHeight: "100vh",
        background:
          "linear-gradient(145deg,#060414 0%,#1a0a3c 40%,#0c1a3c 70%,#060414 100%)",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        padding: "clamp(12px,3vh,24px) clamp(8px,2vw,20px)",
        fontFamily: "'Nunito',sans-serif",
        position: "relative",
        overflow: "hidden",
        boxSizing: "border-box",
      }}
    >
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Bubblegum+Sans&family=Nunito:wght@400;600;700;800;900&display=swap');
        *, *::before, *::after { box-sizing:border-box; }
        .flip-book .stf__parent { border-radius:4px; }

        @keyframes float {
          0%,100% { transform:translateY(0) rotate(0deg); }
          50%      { transform:translateY(-10px) rotate(4deg); }
        }
        @keyframes twinkle {
          0%,100% { opacity:0.35; transform:scale(1); }
          50%      { opacity:0.9;  transform:scale(1.25); }
        }
        @keyframes pulse-btn {
          0%,100% { box-shadow:0 0 0 0 rgba(167,139,250,0.45); }
          50%      { box-shadow:0 0 0 14px rgba(167,139,250,0); }
        }
        @keyframes glow-bar {
          0%,100% { opacity:0.8; }
          50%      { opacity:1; }
        }
      `}</style>

      {/* ambient background orbs */}
      <div
        style={{
          position: "fixed",
          inset: 0,
          pointerEvents: "none",
          overflow: "hidden",
        }}
      >
        <div
          style={{
            position: "absolute",
            top: "-20%",
            left: "-10%",
            width: "50vw",
            height: "50vw",
            borderRadius: "50%",
            background:
              "radial-gradient(circle,rgba(124,58,237,0.18) 0%,transparent 70%)",
          }}
        />
        <div
          style={{
            position: "absolute",
            bottom: "-15%",
            right: "-10%",
            width: "45vw",
            height: "45vw",
            borderRadius: "50%",
            background:
              "radial-gradient(circle,rgba(6,182,212,0.14) 0%,transparent 70%)",
          }}
        />
      </div>

      {/* floating stars */}
      {["⭐", "🌟", "✨", "💫", "🌙", "⭐", "✨", "🌟"].map((e, i) => (
        <div
          key={i}
          style={{
            position: "fixed",
            top: `${6 + i * 11}%`,
            left: i % 2 === 0 ? `${2 + i * 3}%` : `${82 + i}%`,
            fontSize: `clamp(14px,${1.2 + i * 0.3}vw,26px)`,
            animation: `twinkle ${2 + i * 0.35}s ease-in-out infinite`,
            animationDelay: `${i * 0.28}s`,
            pointerEvents: "none",
            opacity: 0.35,
          }}
        >
          {e}
        </div>
      ))}

      {/* ── TITLE ─────────────────────────────────────── */}
      <div
        style={{
          color: "#fff",
          fontFamily: "'Bubblegum Sans',cursive",
          fontSize: "clamp(20px,4vw,38px)",
          fontWeight: 400,
          marginBottom: "clamp(8px,1.5vh,16px)",
          textShadow: "0 2px 24px rgba(167,139,250,0.7)",
          letterSpacing: "0.04em",
          textAlign: "center",
          animation: "float 4s ease-in-out infinite",
          lineHeight: 1.2,
        }}
      >
        📖 Magic Story Book
      </div>

      {/* ── PROGRESS BAR ──────────────────────────────── */}
      <div
        style={{
          width: Math.min(spreadW, window.innerWidth * 0.95),
          height: 6,
          background: "rgba(255,255,255,0.09)",
          borderRadius: 3,
          marginBottom: "clamp(8px,1.5vh,14px)",
          overflow: "hidden",
        }}
      >
        <div
          style={{
            width: `${bookProgress * 100}%`,
            height: "100%",
            background: "linear-gradient(90deg,#7c3aed,#06b6d4,#7c3aed)",
            backgroundSize: "200% 100%",
            borderRadius: 3,
            transition: "width 0.45s ease",
            animation: "glow-bar 2s ease-in-out infinite",
          }}
        />
      </div>

      {/* ── THE BOOK ──────────────────────────────────── */}
      <div
        style={{
          filter:
            "drop-shadow(0 24px 48px rgba(0,0,0,0.65)) drop-shadow(0 8px 20px rgba(124,58,237,0.25))",
          position: "relative",
          flexShrink: 0,
        }}
      >
        <HTMLFlipBook
          ref={flipRef}
          width={pageW}
          height={pageH}
          size="fixed"
          minWidth={1500}
          minHeight={240}
          maxWidth={700}
          maxHeight={1500}
          drawShadow
          flippingTime={650}
          usePortrait={portrait}
          startZIndex={10}
          autoSize={false}
          mobileScrollSupport={false}
          onFlip={onPage}
          className="flip-book"
          style={{ margin: "0 auto" }}
          startPage={0}
        >
          {bookWithCovers.map((item, idx) => {
            const isCover = item.type === "cover";
            return (
              <div
                key={item.id}
                style={{
                  width: pageW,
                  height: pageH,
                  background: isCover ? "transparent" : "#fff",
                }}
              >
                {isCover ? (
                  <CoverPage
                    type={item.isFrontCover ? "front" : "end"}
                    pageW={pageW}
                    pageH={pageH}
                  />
                ) : (
                  <BookPage
                    page={item}
                    pageNum={idx}
                    total={totalBookPages}
                    pageW={pageW}
                    pageH={pageH}
                    onShowRef={item.reference ? () => setShowRef(true) : null}
                  />
                )}
              </div>
            );
          })}
        </HTMLFlipBook>
      </div>

      <div
        style={{
          color: "rgba(255,255,255,0.45)",
          fontSize: "clamp(11px,1.5vw,14px)",
          marginTop: "clamp(6px,1vh,10px)",
          fontWeight: 600,
        }}
      >
        {currentPage === 0 ? "Cover" : currentPage === totalBookPages - 1 ? "End Cover" : `Page ${currentPage} of ${totalBookPages - 2}`}
      </div>

      <div
        style={{
          display: "flex",
          gap: "clamp(8px,2vw,18px)",
          marginTop: "clamp(10px,2vh,18px)",
          alignItems: "center",
          flexWrap: "wrap",
          justifyContent: "center",
        }}
      >
        <NavBtn onClick={prev} label="◀ Prev" disabled={currentPage === 0} />

        <button
          onClick={() => setShowIndex(true)}
          style={{
            width: "clamp(44px,6vw,58px)",
            height: "clamp(44px,6vw,58px)",
            borderRadius: "50%",
            background: "linear-gradient(135deg,#7c3aed,#06b6d4)",
            border: "none",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontSize: "clamp(18px,3vw,26px)",
            cursor: "pointer",
            boxShadow:
              "0 0 0 4px rgba(124,58,237,0.35), 0 8px 24px rgba(0,0,0,0.4)",
            transition: "transform 0.15s",
            title: "Table of Contents",
          }}
          title="Table of Contents"
        >
          📚
        </button>

        <NavBtn
          onClick={next}
          label="Next ▶"
          disabled={currentPage >= totalBookPages - 1}
        />
      </div>


      <button
        onClick={() => (isLoggedIn ? setShowAdmin(true) : setShowLogin(true))}
        style={{
          position: "fixed",
          bottom: "clamp(14px,3vh,24px)",
          right: "clamp(14px,3vw,24px)",
          background: "linear-gradient(135deg,#7c3aed,#2563eb)",
          border: "none",
          color: "#fff",
          borderRadius: "clamp(10px,2vw,15px)",
          padding: "clamp(8px,1.5vh,12px) clamp(14px,2.5vw,20px)",
          cursor: "pointer",
          fontWeight: 800,
          fontSize: "clamp(12px,1.6vw,14px)",
          fontFamily: "'Nunito',sans-serif",
          boxShadow: "0 4px 24px rgba(124,58,237,0.55)",
          animation: "pulse-btn 2.5s infinite",
          display: "flex",
          alignItems: "center",
          gap: 7,
          zIndex: 500,
        }}
      >
         {isLoggedIn ? "Admin Panel" : "Admin"}
      </button>

      <KeyboardNav onPrev={prev} onNext={next} />

      {showIndex && (
        <BookIndex
          pages={pages}
          currentPage={currentPage - 1}
          onGoTo={(pageIndex) => goToPage(pageIndex + 1)}
          onClose={() => setShowIndex(false)}
        />
      )}

      {showRef && activePage?.reference && (
        <ReferencePanel
          reference={activePage.reference}
          onClose={() => setShowRef(false)}
        />
      )}

      {showLogin && (
        <LoginScreen
          onLogin={() => {
            setIsLoggedIn(true);
            setShowLogin(false);
            setShowAdmin(true);
          }}
          onClose={() => setShowLogin(false)}
        />
      )}

      {showAdmin && (
        <AdminPanel
          pages={pages}
          setPages={setPages}
          onClose={() => setShowAdmin(false)}
        />
      )}
    </div>
  );
}
